def validate_access_token(token_string):
    """Validate an access token by checking the database."""
    if not token_string:
        return None

    token_hash = AccessToken.hash_token(token_string)
    token = AccessToken.query.filter_by(token_hash=token_hash).first()

    if token and token.is_valid():
        return token
    return None


def extract_token_from_request():
    """Extract Bearer token from Authorization header or query parameter."""
    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Bearer '):
        return auth_header[7:].strip()

    # Fallback: check query parameter (not recommended for production)
    token = request.args.get('access_token')
    if token:
        return token.strip()

    return None


