@app.route('/oauth/token', methods=['POST'])
def token_endpoint():
    """
    OAuth 2.0 Token endpoint.
    Supports grant_type: client_credentials, refresh_token
    """
    grant_type = request.form.get('grant_type')

    if grant_type == 'client_credentials':
        return handle_client_credentials()
    elif grant_type == 'refresh_token':
        return handle_refresh_token()
    else:
        return jsonify({
            'error': 'unsupported_grant_type',
            'error_description': f'Grant type "{grant_type}" is not supported. Use "client_credentials" or "refresh_token".'
        }), 400


def handle_client_credentials():
    """Handle client_credentials grant type."""
    # Extract client credentials from Basic auth or form body
    client_id = None
    client_secret = None

    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Basic '):
        import base64
        try:
            decoded = base64.b64decode(auth_header[6:]).decode('utf-8')
            client_id, client_secret = decoded.split(':', 1)
        except (ValueError, UnicodeDecodeError):
            pass

    if not client_id:
        client_id = request.form.get('client_id')
        client_secret = request.form.get('client_secret')

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()

    if not client or not client.verify_client_secret(client_secret):
        log_audit_event('AUTH_CLIENT_FAILED', client_id=client_id)
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    if not client.is_active:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client has been deactivated.'
        }), 401

    # Determine scopes
    requested_scopes = request.form.get('scope', '').split()
    allowed_scopes = client.get_allowed_scopes()

    if requested_scopes:
        invalid_scopes = [s for s in requested_scopes if s not in allowed_scopes]
        if invalid_scopes:
            return jsonify({
                'error': 'invalid_scope',
                'error_description': f'Scopes not allowed: {", ".join(invalid_scopes)}'
            }), 400
        granted_scopes = requested_scopes
    else:
        granted_scopes = allowed_scopes

    token_response = issue_token_pair(client, granted_scopes)
    log_audit_event('TOKEN_ISSUED', client_id=client_id, details=f'Scopes: {", ".join(granted_scopes)}')

    return jsonify(token_response), 200


def handle_refresh_token():
    """Handle refresh_token grant type."""
    refresh_token_string = request.form.get('refresh_token')
    if not refresh_token_string:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'refresh_token is required.'
        }), 400

    # Authenticate client
    client_id = request.form.get('client_id')
    client_secret = request.form.get('client_secret')

    auth_header = request.headers.get('Authorization', '')
    if auth_header.startswith('Basic '):
        import base64
        try:
            decoded = base64.b64decode(auth_header[6:]).decode('utf-8')
            client_id, client_secret = decoded.split(':', 1)
        except (ValueError, UnicodeDecodeError):
            pass

    if not client_id or not client_secret:
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Client credentials are required.'
        }), 401

    client = OAuthClient.query.filter_by(client_id=client_id).first()
    if not client or not client.verify_client_secret(client_secret):
        return jsonify({
            'error': 'invalid_client',
            'error_description': 'Invalid client credentials.'
        }), 401

    # Validate refresh token
    token_hash = RefreshToken.hash_token(refresh_token_string)
    refresh_token = RefreshToken.query.filter_by(token_hash=token_hash).first()

    if not refresh_token or not refresh_token.is_valid():
        return jsonify({
            'error': 'invalid_grant',
            'error_description': 'The refresh token is invalid or expired.'
        }), 400

    if refresh_token.client_id != client.id:
        return jsonify({
            'error': 'invalid_grant',
            'error_description': 'Refresh token does not belong to this client.'
        }), 400

    # Revoke old tokens
    old_access_token = refresh_token.access_token
    old_access_token.revoked = True
    refresh_token.revoked = True

    # Issue new token pair
    scopes = old_access_token.get_scopes()
    token_response = issue_token_pair(client, scopes, user_id=old_access_token.user_id)

    db.session.commit()
    log_audit_event('TOKEN_REFRESHED', client_id=client_id)

    return jsonify(token_response), 200


@app.route('/oauth/revoke', methods=['POST'])
def revoke_endpoint():
    """OAuth 2.0 Token Revocation endpoint (RFC 7009)."""
    token_string = request.form.get('token')
    token_type_hint = request.form.get('token_type_hint', 'access_token')

    if not token_string:
        return jsonify({
            'error': 'invalid_request',
            'error_description': 'token parameter is required.'
        }), 400

    token_hash = hashlib.sha256(token_string.encode()).hexdigest()

    revoked = False

    if token_type_hint == 'access_token':
        access_token = AccessToken.query.filter_by(token_hash=token_hash).first()
        if access_token:
            access_token.revoked = True
            # Also revoke associated refresh token
            if access_token.refresh_token:
                access_token.refresh_token.revoked = True
            revoked = True
    elif token_type_hint == 'refresh_token':
        refresh_token = RefreshToken.query.filter_by(token_hash=token_hash).first()
        if refresh_token:
            refresh_token.revoked = True
            refresh_token.access_token.revoked = True
            revoked = True

    # If hint didn't match, try the other type
    if not revoked:
        access_token = AccessToken.query.filter_by(token_hash=token_hash).first()
        if access_token:
            access_token.revoked = True
            if access_token.refresh_token:
                access_token.refresh_token.revoked = True
            revoked = True
        else:
            refresh_token = RefreshToken.query.filter_by(token_hash=token_hash).first()
            if refresh_token:
                refresh_token.revoked = True
                refresh_token.access_token.revoked = True
                revoked = True

    if revoked:
        db.session.commit()
        log_audit_event('TOKEN_REVOKED')

    # RFC 7009: always return 200, even if token was not found
    return jsonify({'status': 'ok'}), 200


@app.route('/oauth/introspect', methods=['POST'])
def introspect_endpoint():
    """OAuth 2.0 Token Introspection endpoint (RFC 7662)."""
    token_string = request.form.get('token')
    if not token_string:
        return jsonify({'active': False}), 200

    token_hash = AccessToken.hash_token(token_string)
    token = AccessToken.query.filter_by(token_hash=token_hash).first()

    if token and token.is_valid():
        return jsonify({
            'active': True,
            'scope': ' '.join(token.get_scopes()),
            'client_id': token.client.client_id,
            'username': token.user_id,
            'token_type': 'Bearer',
            'exp': int(token.expires_at.timestamp()),
            'iat': int(token.created_at.timestamp()),
            'sub': token.user_id
        }), 200

    return jsonify({'active': False}), 200


