@app.route('/api/v1/admin/clients', methods=['POST'])
@require_oauth('admin')
def register_client():
    """Admin endpoint: Register a new OAuth client."""
    data = request.get_json()
    if not data:
        return jsonify({'error': 'Request body is required.'}), 400

    client_name = data.get('client_name')
    allowed_scopes = data.get('allowed_scopes', [])

    if not client_name:
        return jsonify({'error': 'client_name is required.'}), 400

    new_client_id = secrets.token_urlsafe(24)
    new_client_secret = secrets.token_urlsafe(48)

    client = OAuthClient(
        client_id=new_client_id,
        client_name=client_name,
        allowed_scopes=','.join(allowed_scopes)
    )
    client.set_client_secret(new_client_secret)

    db.session.add(client)
    db.session.commit()

    log_audit_event('CLIENT_REGISTERED', client_id=new_client_id, details=f'Client name: {client_name}')

    return jsonify({
        'client_id': new_client_id,
        'client_secret': new_client_secret,
        'client_name': client_name,
        'allowed_scopes': allowed_scopes,
        'message': 'Store the client_secret securely. It cannot be retrieved again.'
    }), 201


@app.route('/api/v1/admin/clients/<client_id>/deactivate', methods=['POST'])
@require_oauth('admin')
def deactivate_client(client_id):
    """Admin endpoint: Deactivate an OAuth client."""
    client = OAuthClient.query.filter_by(client_id=client_id).first()
    if not client:
        return jsonify({'error': 'Client not found.'}), 404

    client.is_active = False

    # Revoke all active tokens for this client
    AccessToken.query.filter_by(client_id=client.id, revoked=False).update({'revoked': True})
    RefreshToken.query.filter_by(client_id=client.id, revoked=False).update({'revoked': True})

    db.session.commit()

    log_audit_event('CLIENT_DEACTIVATED', client_id=client_id)

    return jsonify({'status': 'deactivated', 'client_id': client_id}), 200


@app.route('/api/v1/admin/audit-log', methods=['GET'])
@require_oauth('admin')
def get_audit_log():
    """Admin endpoint: View audit log."""
    limit = request.args.get('limit', 50, type=int)
    offset = request.args.get('offset', 0, type=int)
    event_type = request.args.get('event_type')

    query = AuditLog.query.order_by(AuditLog.created_at.desc())

    if event_type:
        query = query.filter_by(event_type=event_type)

    total = query.count()
    logs = query.offset(offset).limit(limit).all()

    return jsonify({
        'audit_logs': [
            {
                'id': log.id,
                'event_type': log.event_type,
                'client_id': log.client_id,
                'user_id': log.user_id,
                'endpoint': log.endpoint,
                'ip_address': log.ip_address,
                'details': log.details,
                'created_at': log.created_at.isoformat()
            }
            for log in logs
        ],
        'total': total,
        'limit': limit,
        'offset': offset
    }), 200


