# ---- Cleanup Task ----

def cleanup_expired_tokens():
    """Remove expired tokens from the database."""
    now = datetime.utcnow()
    expired_access = AccessToken.query.filter(AccessToken.expires_at < now).delete()
    expired_refresh = RefreshToken.query.filter(RefreshToken.expires_at < now).delete()
    db.session.commit()
    return expired_access, expired_refresh


