    with app.app_context():
        init_db()

    port = int(os.environ.get('PORT', 5000))
    debug = os.environ.get('FLASK_DEBUG', 'true').lower() == 'true'

    print(f"\n{'='*60}")
    print(f"OAuth 2.0 Resource Server / API Gateway")
    print(f"Running on http://0.0.0.0:{port}")
    print(f"{'='*60}")
    print(f"\nEndpoints:")
    print(f"  POST /oauth/token          - Obtain access token")
    print(f"  POST /oauth/revoke         - Revoke a token")
    print(f"  POST /oauth/introspect     - Introspect a token")
    print(f"  GET  /api/v1/health        - Health check (public)")
    print(f"  GET  /api/v1/services      - List services (scope: read)")
    print(f"  POST /api/v1/services/<name>/route - Route request (scope: read,write)")
    print(f"  GET  /api/v1/users/me      - Current user info (scope: profile)")
    print(f"  GET  /api/v1/admin/clients - List clients (scope: admin)")
    print(f"  POST /api/v1/admin/clients - Register client (scope: admin)")
    print(f"{'='*60}\n")

    app.run(host='0.0.0.0', port=port, debug=debug)